   361→    return isMphInch ? UnitType.mphInch : UnitType.kmhCm;
   362→  }
   363→
   364→  @override
   365→  Locale? getLocaleLanguage() {
   366→    final savedLocaleLanguage =
   367→        _sharedPreferences.getString(ProfileStorage.prefsKeyLocaleLanguage);
   368→
