    88→      String email, String password, bool saveCredentials) async {
    89→    final methodFc = _fc.category('SIP');
    90→
    91→    // Run the query and return result.
    92→    final result = await _runner.runQuery(
    93→      () async {
    94→        if (await AuthUtils.instance.isSignedIn()) {
    95→          await AuthUtils.instance.signOut();
    96→        }
    97→        await Amplify.Auth.signIn(
    98→          username: email,
    99→          password: password,
   100→          options: const SignInOptions(
   101→            pluginOptions: CognitoSignInPluginOptions(
   102→              authFlowType: AuthenticationFlowType.userPasswordAuth,
   103→            ),
   104→          ),
   105→        );
   106→      },
   107→      false,
   108→    );
   109→    if (result.hasLeft) {
   110→      if (result.left is NetworkFailure) {
   111→        return Left(Failure.network(
   112→          code: methodFc.position('001'),
   113→          description: (l10n) =>
   114→              l10n.auth_client__failed_to_authenticate_check_network,
   115→          underlyingException: result.left.underlyingException,
   116→        ));
   117→      }
   118→      if (result.left is InvalidSessionFailure) {
   119→        final e = result.left.underlyingException;
   120→        if (e is AuthException) {
   121→          return Left(await _processAuthException(e, email));
   122→        }
   123→      }
   124→      return Left(result.left);
   125→    }
   126→
   127→    late String userId;
   128→    try {
   129→      userId = await AuthUtils.instance.getUserId();
   130→    } catch (e, stackTrace) {
   131→      _logger.e('failed to get userId', ex: e, stacktrace: stackTrace);
   132→      return Left(Failure.undefined(
   133→        code: methodFc.position('002'),
   134→        underlyingException: e,
   135→        stackTrace: stackTrace,
   136→      ));
   137→    }
   138→
   139→    await _profileStorage.setEmail(email);
   140→    if (saveCredentials) {
   141→      // Cache user password
   142→      await _profileStorage.setPassword(password);
   143→    } else {
   144→      // Remove cached user password
   145→      await _profileStorage.setPassword(null);
   146→    }
   147→
   148→    await _profileStorage.setUserId(userId);
   149→
   150→    // Get team_id and role of the user using direct API call
   151→    // This avoids circular dependency with Repository
   152→    final userInfoResult = await _apiClient.request(
   153→      method: 'GET',
   154→      path: '/users/me',
   155→      responseMapper: UserDetailResponse.fromJson,
   156→    );
   157→    if (userInfoResult.hasLeft) {
   158→      return Left(userInfoResult.left);
   159→    }
   160→
   161→    final user = userInfoResult.right.user;
   162→    final teamId = user.teams
   163→        .where((t) =>
   164→            user.givenUserRoles[t.id!]
   165→                ?.where((r) => !r.deleteFlag)
   166→                .isNotEmpty ??
   167→            false)
   168→        .firstOrNull
   169→        ?.id;
