   177→    // Cache team_id and role
   178→    await _profileStorage.setTeamId(teamId);
   179→
   180→    return const Right(true);
   181→  }
   182→
   183→  Future<Failure> _processAuthException(AuthException e, String email) async {
   184→    final methodFc = _fc.category('PAEX');
   185→
   186→    final isPasswordIncorrect = e is AuthNotAuthorizedException ||
   187→        (e is UserNotFoundException &&
   188→            e.message == "UserMigration failed with error Incorrect password.");
   189→    final isUserNotFound =
   190→        e is UserNotFoundException && e.message == "User does not exist.";
   191→
   192→    if (isPasswordIncorrect) {
   193→      // パスワードが間違っている場合でも、メール確認状況をチェック
   194→      final emailStatusResult = await _getEmailVerificationStatus(email);
   195→      // もしメール未確認の場合は、そちらのエラーを返す
   196→      if (emailStatusResult is UnconfirmedEmailFailure) {
   197→        return emailStatusResult;
   198→      }
   199→      // それ以外の場合は、パスワード間違いエラーを返す
   200→      return Failure.incorrectPassword(
   201→        code: methodFc.position('001'),
   202→        email: email,
   203→      );
   204→    }
   205→    if (isUserNotFound) {
   206→      return await _getEmailVerificationStatus(email);
   207→    }
   208→
   209→    // アカウント削除後にユーザーが削除予定に入っている場合に signIn しようとすると
   210→    // このエラーになる。この場合は未登録メールアドレスエラーを返す。
   211→    final errorCode = methodFc.position('003');
   212→    if (errorCode == 'EM-AAC-PAEX-003') {
   213→      return Failure.unregisteredEmail(
   214→        code: errorCode,
   215→        email: email,
   216→      );
   217→    }
   218→
   219→    // それ以外の認証エラーは UndefinedFailure として扱う
   220→    return Failure.undefined(
   221→      code: methodFc.position('004'),
   222→      description: (l10n) =>
   223→          l10n.auth_client__failed_to_authenticate_received_error_response,
   224→      underlyingException: e,
   225→    );
   226→  }
   227→
   228→  Future<Failure> _getEmailVerificationStatus(String email) async {
   229→    final methodFc = _fc.category('GVS');
   230→
   231→    // Run the query and return result.
   232→    final result = await _apiClient.request(
   233→      method: 'GET',
   234→      path:
   235→          '/auth/users/verification-status?email=${Uri.encodeQueryComponent(email)}',
   236→      responseMapper: EmailVerificationStatusResponse.fromJson,
   237→      authenticated: false,
   238→    );
   239→    if (result.hasLeft) {
   240→      return result.left;
   241→    }
   242→
   243→    final status = result.right.status;
   244→    switch (status) {
   245→      case EmailVerificationStatus.notVerified:
   246→        return Failure.unconfirmedEmail(
   247→          code: methodFc.position('001'),
   248→          email: email,
   249→        );
   250→      case EmailVerificationStatus.notCreated:
   251→        return Failure.unregisteredEmail(
   252→          code: methodFc.position('002'),
   253→          email: email,
   254→        );
   255→      default:
   256→        return Failure.undefined(
   257→          code: methodFc.position('003'),
   258→          description: (l10n) => l10n.auth_client__unknown_verification_status,
   259→        );
   260→    }
   261→  }
   262→
   263→  @override
   264→
   265→  /// Sign out user from application
   266→  Future<Result<Failure, bool>> signOut() async {
   267→    // TODO: After disconnecting network,
   268→    // goTrueClient.signOut() throws a network exception at the first call,
   269→    // but this method return null without any exceptions at the second call.
   270→
   271→    // Run the query and return result.
   272→    final result = await _runner.runQuery(
   273→      () => AuthUtils.instance.signOut(),
   274→    );
   275→    // Delete cache regardless of the result
   276→    await Future.wait([
   277→      _profileStorage.setUserId(null),
   278→      _profileStorage.setTeamId(null),
   279→    ]);
   280→    if (result.hasLeft) {
   281→      return Left(result.left);
   282→    } else {
   283→      return const Right(true);
   284→    }
   285→  }
   286→
   287→  @override
   288→  Future<Result<Failure, bool>> changePassword(
   289→      {required String newPassword, required bool saveCredentials}) async {
   290→    // Run the query and return result.
   291→    final result = await _apiClient.request(
   292→      method: 'PUT',
   293→      path: '/users/me/password',
   294→      data: PasswordChangeRequest(
   295→        password: newPassword,
   296→        passwordConfirmation: newPassword,
   297→      ).toJson(),
   298→    );
   299→    if (result.hasLeft) {
   300→      return Left(result.left);
   301→    }
   302→
   303→    if (saveCredentials) {
   304→      // Save if we need to save credentials
   305→      await _profileStorage.setPassword(newPassword);
   306→    } else {
   307→      // Remove cached user password
   308→      await _profileStorage.setPassword(null);
   309→    }
   310→    return const Right(true);
   311→  }
   312→
   313→  @override
   314→  Future<Result<Failure, bool>> forgotPassword({required String email}) async {
   315→    // Run the query and return result.
   316→    final result = await _apiClient.request(
   317→      method: 'POST',
   318→      path: '/auth/password-reset/email',
   319→      data: PasswordResetRequest(
   320→        email: email,
   321→      ).toJson(),
   322→      authenticated: false,
   323→    );
   324→    if (result.hasLeft) {
   325→      return Left(result.left);
   326→    }
   327→    return const Right(true);
   328→  }
   329→
   330→  @override
   331→  Future<Result<Failure, String>> signUp({
   332→    required String email,
   333→    required String password,
   334→    required DateTime birthday,
   335→  }) async {
   336→    // Run the query and return result.
   337→    final result = await _apiClient.request(
   338→      method: 'POST',
   339→      path: '/auth/signup',
   340→      data: SignUpRequest(
   341→        name: email,
   342→        email: email,
   343→        password: password,
   344→        birthday: birthday,
   345→      ).toJson(),
   346→      responseMapper: SignUpResponse.fromJson,
   347→      authenticated: false,
   348→    );
   349→    if (result.hasLeft) {
   350→      return Left(result.left);
   351→    }
   352→
   353→    final userId = result.right.userId;
   354→    await Future.wait([
   355→      _profileStorage.setIsInSignUpFlow(true),
   356→      _profileStorage.setEmail(email),
   357→      _profileStorage.setUserId(userId),
   358→      _profileStorage.setPassword(password),
   359→      _profileStorage.setBirthday(birthday),
   360→    ]);
   361→    return Right(userId);
   362→  }
   363→
   364→  @override
   365→  Future<Result<Failure, String>> verifyCode({
   366→    required String code,
   367→  }) async {
   368→    assert(_profileStorage.getIsInSignUpFlow() ?? false);
   369→
   370→    final email = await _profileStorage.getEmail();
   371→    assert(email != null);
   372→
   373→    // Run the query and return result.
   374→    final result = await _apiClient.request(
   375→      method: 'GET',
   376→      path: '/auth/code-verification',
   377→      queryParameters: VerifyCodeRequest(
   378→        email: email!,
   379→        code: code,
   380→      ).toJson(),
   381→      responseMapper: VerifyCodeResponse.fromJson,
   382→      authenticated: false,
   383→    );
   384→    if (result.hasLeft) {
   385→      return Left(result.left);
   386→    }
   387→    return Right(result.right.token);
   388→  }
   389→
   390→  @override
   391→  Future<Result<Failure, void>> completeSignUp({required String token}) async {
   392→    assert(_profileStorage.getIsInSignUpFlow() ?? false);
   393→
   394→    final userId = _profileStorage.getUserId();
   395→    final password = await _profileStorage.getPassword();
   396→
   397→    assert(userId != null);
   398→    assert(password != null);
   399→
   400→    // Run the query and return result.
   401→    final result = await _apiClient.request(
   402→      method: 'PUT',
   403→      path: '/auth/password-reset/initial',
   404→      data: SetUserInitialPasswordRequest(
   405→        userId: userId!,
   406→        password: password!,
   407→        token: token,
   408→      ).toJson(),
   409→      authenticated: false,
   410→    );
   411→    await _profileStorage.setIsInSignUpFlow(false);
   412→    if (result.hasLeft) {
   413→      return Left(result.left);
   414→    }
   415→    return Right(null);
   416→  }
   417→
   418→  @override
   419→  Future<Result<Failure, bool>> deleteAccount() async {
   420→    // Run the query and return result.
   421→    final result = await _apiClient.request(
   422→      method: 'DELETE',
   423→      path: '/users/me',
   424→    );
   425→    if (result.hasLeft) {
   426→      return Left(result.left);
   427→    }
   428→
   429→    // Sign out and clear all cached data after successful account deletion
   430→    await Future.wait([
   431→      AuthUtils.instance.signOut(),
   432→      _profileStorage.setUserId(null),
   433→      _profileStorage.setTeamId(null),
   434→      _profileStorage.setEmail(null),
   435→      _profileStorage.setPassword(null),
   436→      _profileStorage.setIsInSignUpFlow(false),
   437→    ]);
   438→
   439→    return const Right(true);
   440→  }
   441→
   442→  @override
   443→  Future<bool> get isLoggedIn async {
   444→    return await AuthUtils.instance.isSignedIn();
   445→  }
   446→}
